  ('disabled-64311456-moex-00065', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '依據我國兒童及少年福利與權益保障法的規定，酒家、特種咖啡茶室、成 人用品零售店、限制級電子遊戲場及其他涉及賭博、色情、暴力等經主管 機關認定足以危害兒童及少年身心健康之場所，應距離幼兒園、國民中小 學、高中、職校至少多少距離以上，並檢附證明文件，經商業登記主管機 關登記後，始得營業：', '["一百公尺", "兩百公尺", "三百公尺", "五百公尺"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00066', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '依據我國身心障礙者權益保障法的規定，身心障礙者於遭到遺棄，且情況 危急非立即給予保護、安置或其他處置，其生命、身體或自由有立即之危 險或有危險之虞者，直轄市、縣（市）主管機關應予緊急保護、安置或為 其他必要之處置；上述之緊急保護安置，若未經過法院裁定，不得超過多 久時間？', '["二十四小時", "三十六小時", "四十八小時", "七十二小時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00067', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '甲於工作職場上遭受直屬主管乙的性騷擾，但因行為人乙是自己的主管， 所以甲一直隱忍不敢對外張揚，最後終於忍無可忍想提出申訴，請問甲至 遲應自乙對甲有性騷擾事件發生之日起幾年內提出申訴？', '["三年", "五年", "七年", "十年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00068', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '普遍公認為世界上最早的社會保障法，標誌著社會救濟制度的建立，將諸多 對無工作者、流浪者、乞丐等窮人的資助法令集合成文（慣稱「伊莉莎白43 號法案」），請問該項法令公布時間是在那一年？', '["1349年的勞工法", "1536年的公共救助法", "1601年的濟貧法", "1881年社會保險詔書"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00069', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '甲為列冊低收入戶，具有工作能力且接受政府轉介相關就業服務，請問若 未經評估確有必要，甲因此而增加的工作收入，最長於多久期間內得免計 入家庭總收入？', '["六個月", "一年", "兩年", "三年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00070', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '依據我國的國民年金法的規定，下列何者給付不在國民年金法的給付範 圍內？', '["遺屬年金給付", "身心障礙年金給付", "喪葬給付", "住院傷病給付"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00071', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '根據全民健康保險法規定，保險醫事服務機構對本保險所提供之醫療給付 ，除全民健康保險法另有規定外，不得自立名目向保險對象收取費用。若 有違反者，應退還已收取之費用，並按所收取之費用處以幾倍罰鍰？', '["二十倍", "十五倍", "十倍", "五倍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00072', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '依據我國長期照顧服務法的定義，需要長期照顧者是指身心失能持續已達 或預期達多少期間以上者，依其個人或其照顧者之需要，所提供之生活支 持、協助、社會參與、照顧及相關之醫護服務：', '["一個月", "三個月", "六個月", "一年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00073', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '根據LeGrand（1982）的分類，政府在推動社會政策的平等時，如果是利 用富人多交稅，而窮人在接受福利後，縮小富人與窮人之間的所得差距， 是屬於下列那一種策略？', '["結果的平等", "公共支出的平等", "最終所得的平等", "成本的平等"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00074', 'disabled-64311456', 'disabled-64311456-moex-114-e718b90b', 'sub-disabled-64311456-03', NULL, 'single_choice', '請問下列那一個社會政策制定過程模式的看法，被批評為：看起來似乎有 邏輯，對於政策的來由都有相關解釋，但是，太過單純地將問題導向於政 策的過程，這與真實世界裡的運作不符：', '["政治經濟模式", "衝突理論模式", "漸進主義模式", "理性決策模式"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b6d0a68dd6db", "answer_pdf_sha1": "31551f222ba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL)
